module top_module(
   input         clock, reset, load,
   input [15:0]  loadValue,
   output [15:0] count,
   output        flag);reg [15:0]    unused_countReg = 16'b0;
   wire          flagWire;

   assign flag = flagWire;
   assign count = unused_countReg;

   always @ (posedge clock) begin 
      if (reset)
         unused_countReg <= 16'b0;
      else if (load)
         unused_countReg <= loadValue;
      else if (unused_countReg == {16{1'b1}})
         unused_countReg <= 16'b0;
      else
         unused_countReg <= unused_countReg + 1;
   end

   assign flagWire = (unused_countReg == {16{1'b1}});

endmodule
